import React, { useState, useCallback, useMemo } from 'react';
import { InputMethod, TranscriptionSegment } from './types';
import { fileToBase64, fetchAndEncodeAudio } from './utils/audioUtils';
import { transcribeAudio } from './services/geminiService';

// --- SVG Icons --- //
