  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
  </svg>
);

const InfoIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
);

const Spinner = () => (
  <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-sky-600"></div>
);

// --- Helper Components --- //

interface InputModeToggleProps {
  selectedMode: InputMethod;
  onModeChange: (mode: InputMethod) => void;
  disabled: boolean;
}
const InputModeToggle: React.FC<InputModeToggleProps> = ({ selectedMode, onModeChange, disabled }) => {
  const baseClasses = "flex-1 px-4 py-2.5 text-sm font-semibold flex items-center justify-center transition-colors duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-sky-500";
  const activeClasses = "bg-sky-600 text-white shadow-md";
  const inactiveClasses = "bg-slate-200 text-slate-600 hover:bg-slate-300";

  return (
    <div className="flex w-full rounded-lg overflow-hidden border border-slate-300">
      <button
        onClick={() => onModeChange(InputMethod.File)}
        disabled={disabled}
        className={`${baseClasses} rounded-l-lg ${selectedMode === InputMethod.File ? activeClasses : inactiveClasses}`}
      >
        <UploadIcon /> ファイルをアップロード
      </button>
      <button
        onClick={() => onModeChange(InputMethod.Url)}
        disabled={disabled}
        className={`${baseClasses} rounded-r-lg ${selectedMode === InputMethod.Url ? activeClasses : inactiveClasses}`}
      >
        <LinkIcon /> URLから
      </button>
    </div>
  );
};

interface FileInputFormProps {
  file: File | null;
  onFileChange: (file: File | null) => void;
  isLoading: boolean;
}
const FileInputForm: React.FC<FileInputFormProps> = ({ file, onFileChange, isLoading }) => {
    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            onFileChange(e.target.files[0]);
        }
    };

    const handleClearFile = () => {
        onFileChange(null);
        const input = document.getElementById('file-upload') as HTMLInputElement;
        if (input) input.value = '';
    }

    return (
        <div className="w-full">
            <label htmlFor="file-upload" className={`relative flex flex-col items-center justify-center w-full h-32 border-2 border-slate-300 border-dashed rounded-lg cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors ${isLoading ? 'cursor-not-allowed' : ''}`}>
                {file ? (
                    <div className="text-center">
                       <p className="font-semibold text-sky-700">{file.name}</p>
                       <p className="text-xs text-slate-500">{(file.size / 1024).toFixed(2)} KB</p>
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center pt-5 pb-6">
                        <svg className="w-8 h-8 mb-4 text-slate-500" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 20 16"><path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 13h3a3 3 0 0 0 0-6h-.025A5.56 5.56 0 0 0 16 6.5 5.5 5.5 0 0 0 5.207 5.021C5.137 5.017 5.071 5 5 5a4 4 0 0 0 0 8h2.167M10 15V6m0 0L8 8m2-2 2 2"/></svg>
                        <p className="mb-2 text-sm text-slate-500"><span className="font-semibold">クリックしてアップロード</span>またはドラッグ＆ドロップ</p>
                        <p className="text-xs text-slate-500">MP3, WAV, M4Aなど</p>
                    </div>
                )}
                <input id="file-upload" type="file" className="hidden" onChange={handleFileChange} accept="audio/*" disabled={isLoading} />
            </label>
            {file && (
                <button onClick={handleClearFile} disabled={isLoading} className="mt-2 text-xs text-red-500 hover:text-red-700 flex items-center gap-1">
                    <TrashIcon /> 選択をクリア
                </button>
            )}
        </div>
    );
};

interface UrlInputFormProps {
  url: string;
  onUrlChange: (url: string) => void;
  isLoading: boolean;
}
const UrlInputForm: React.FC<UrlInputFormProps> = ({ url, onUrlChange, isLoading }) => (
    <div className="w-full">
        <input
            type="url"
            value={url}
            onChange={(e) => onUrlChange(e.target.value)}
            disabled={isLoading}
            placeholder="https://example.com/audio.mp3"
            className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-sky-500 focus:border-sky-500 transition-shadow"
            aria-label="音声ファイルのURL"
        />
        <div role="alert" className="mt-4 flex items-start p-3 space-x-3 text-sm text-sky-800 bg-sky-50 border border-sky-200 rounded-lg">
            <div className="flex-shrink-0">
                <InfoIcon />
            </div>
            <div>
                <p className="font-semibold">URL入力の仕組み</p>
                <p className="mt-1 text-sky-700">
                    音声サーバーはクロスオリジンリクエスト(CORS)を許可する必要があります。エラーの場合は、ファイルをダウンロードして<strong>ファイルをアップロード</strong>をお試しください。
                </p>
            </div>
        </div>
    </div>
);

// --- Main App Component --- //
export default function App() {
  const [inputMethod, setInputMethod] = useState<InputMethod>(InputMethod.File);
  const [audioFile, setAudioFile] = useState<File | null>(null);
  const [audioUrl, setAudioUrl] = useState<string>('');

  const [summary, setSummary] = useState<string>('');
  const [transcription, setTranscription] = useState<TranscriptionSegment[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [copySuccess, setCopySuccess] = useState<boolean>(false);

  const handleModeChange = (mode: InputMethod) => {
    setInputMethod(mode);
    setError(null);
  };

  const handleClear = () => {
    setAudioFile(null);
    setAudioUrl('');
    setTranscription([]);
    setSummary('');
    setError(null);
    setIsLoading(false);
  };

  const handleTranscribe = useCallback(async () => {
    if ((inputMethod === InputMethod.File && !audioFile) || (inputMethod === InputMethod.Url && !audioUrl)) {
      setError("ファイルを選択するか、URLを入力してください。");
      return;
    }

    setIsLoading(true);
    setError(null);
    setTranscription([]);
    setSummary('');

    try {
      let audioData: { mimeType: string; data: string };

      if (inputMethod === InputMethod.File && audioFile) {
        if (!audioFile.type.startsWith('audio/')) {
            throw new Error('無効なファイル形式です。音声ファイルをアップロードしてください。');
        }
        const mimeType = audioFile.type;
        const base64Data = await fileToBase64(audioFile);
        audioData = { mimeType, data: base64Data };
      } else if (inputMethod === InputMethod.Url && audioUrl) {
        audioData = await fetchAndEncodeAudio(audioUrl);
      } else {
        throw new Error("音声ソースが選択されていません。");
      }

      const result = await transcribeAudio(audioData);
      setTranscription(result.transcription);
      setSummary(result.summary);
    } catch (e) {
      if (e instanceof Error) {
        setError(e.message);
      } else {
        setError("文字起こし中に不明なエラーが発生しました。");
      }
    } finally {
      setIsLoading(false);
    }
  }, [audioFile, audioUrl, inputMethod]);

  const handleCopyToClipboard = () => {
    if (!transcription || transcription.length === 0) return;
    const formattedText = transcription
        .map(segment => `${segment.speaker}: ${segment.transcript}`)
        .join('\n');

    navigator.clipboard.writeText(formattedText).then(() => {
        setCopySuccess(true);
        setTimeout(() => setCopySuccess(false), 2000);
    });
  };

  const isTranscribeDisabled = useMemo(() => {
    if (isLoading) return true;
    if (inputMethod === InputMethod.File) return !audioFile;
    if (inputMethod === InputMethod.Url) return !audioUrl.trim();
    return true;
  }, [isLoading, inputMethod, audioFile, audioUrl]);

  // Define speaker styles with explicit typing to avoid indexing issues in TypeScript.
  const speakerStyles = useMemo<Record<string, { alignment: string; bubble: string }>>(() => {
    const styleMap: Record<string, { alignment: string; bubble: string }> = {};
    if (!transcription || transcription.length === 0) return styleMap;

    const uniqueSpeakers = [...new Set(transcription.map(t => t.speaker))];
    const alignments = ['justify-start', 'justify-end'];
    const bubbles = ['bg-slate-200 text-slate-900', 'bg-sky-600 text-white'];

    uniqueSpeakers.forEach((speaker, index) => {
        styleMap[speaker] = {
            alignment: alignments[index % alignments.length],
            bubble: bubbles[index % bubbles.length],
        };
    });
    return styleMap;
  }, [transcription]);


  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-4 sm:p-6 lg:p-8 font-sans">
      <div className="w-full max-w-2xl mx-auto">
        <header className="text-center mb-8">
          <h1 className="text-4xl font-bold text-slate-800">音声文字起こし</h1>
          <p className="text-slate-500 mt-2">Powered by Google Gemini</p>
        </header>

        <main className="bg-white p-6 sm:p-8 rounded-xl shadow-lg border border-slate-100 space-y-6">
          <div className="space-y-4">
              <InputModeToggle selectedMode={inputMethod} onModeChange={handleModeChange} disabled={isLoading}/>
              {inputMethod === InputMethod.File ? (
                  <FileInputForm file={audioFile} onFileChange={setAudioFile} isLoading={isLoading} />
              ) : (
                  <UrlInputForm url={audioUrl} onUrlChange={setAudioUrl} isLoading={isLoading}/>
              )}
          </div>

          <div className="flex flex-col sm:flex-row items-center gap-4">
            <button
              onClick={handleTranscribe}
              disabled={isTranscribeDisabled}
              className="w-full sm:w-auto flex-grow px-6 py-3 text-white font-semibold bg-sky-600 rounded-lg shadow-md hover:bg-sky-700 disabled:bg-slate-400 disabled:cursor-not-allowed disabled:shadow-none transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-sky-500"
            >
              {isLoading ? '文字起こし中...' : '文字起こしを実行'}
            </button>
            <button
              onClick={handleClear}
              disabled={isLoading && !error}
              className="w-full sm:w-auto px-6 py-3 text-slate-600 font-semibold bg-slate-200 rounded-lg hover:bg-slate-300 disabled:bg-slate-100 disabled:text-slate-400 transition-colors duration-200"
            >
              クリア
            </button>
          </div>

          <div className="pt-6 border-t border-slate-200">
             <h2 className="text-lg font-semibold text-slate-700 mb-3">結果</h2>
             <div className="relative w-full min-h-[150px] p-4 bg-slate-50 rounded-lg border border-slate-200">
                {isLoading && (
                    <div className="absolute inset-0 flex flex-col items-center justify-center bg-white/50 backdrop-blur-sm z-10">
                        <Spinner />
                        <p className="mt-4 text-sm font-semibold text-sky-700 animate-pulse-fast">音声を処理中...</p>
                    </div>
                )}
                {error && (
                    <div className="text-red-600 bg-red-50 p-3 rounded-md">
                        <p className="font-bold">エラー</p>
                        <p>{error}</p>
                    </div>
                )}
                {!isLoading && !error && (
                  <>
                    {summary || transcription.length > 0 ? (
                      <div>
                        {summary && (
                          <div className="mb-6 pb-4 border-b border-slate-200">
                            <h3 className="text-md font-semibold text-slate-600 mb-2">会話の概要</h3>
                            <div className="p-3 bg-slate-100 rounded-lg text-sm text-slate-800">
                              <p className="whitespace-pre-wrap">{summary}</p>
                            </div>
                          </div>
                        )}
                        <div className="space-y-4">
                          {transcription.map((segment: TranscriptionSegment, index: number) => {
                            // Explicitly cast or type speakerStyles to resolve potential indexing issues with 'unknown'.
                            const style = (speakerStyles as Record<string, { alignment: string; bubble: string }>)[segment.speaker] || { alignment: 'justify-start', bubble: 'bg-gray-200' };
                            return (
                                <div key={index} className={`flex w-full ${style.alignment}`}>
                                    <div className={`p-3 rounded-xl shadow-sm max-w-xs md:max-w-md ${style.bubble}`}>
                                        <p className="text-xs font-bold mb-1 opacity-80">{segment.speaker}</p>
                                        <p className="text-sm break-words">{segment.transcript}</p>
                                    </div>
                                </div>
                            )
                          })}
                        </div>
                      </div>
                    ) : (
                       <p className='text-slate-400'>文字起こしされたテキストはここに表示されます...</p>
                    )}
                    {transcription.length > 0 && (
                        <button
                            onClick={handleCopyToClipboard}
                            className="absolute top-2 right-2 p-2 rounded-md bg-slate-200 hover:bg-slate-300 transition-colors"
                            title="クリップボードにコピー"
                        >
                            {copySuccess ? <CheckIcon /> : <CopyIcon />}
                        </button>
                    )}
                  </>
                )}
             </div>
          </div>
        </main>

        <footer className="text-center mt-8">
            <p className="text-xs text-slate-400">これはデモアプリケーションです。文字起こしの精度は異なる場合があります。</p>
        </footer>
      </div>
    </div>
  );
}

export enum InputMethod {
  File = 'file',
  Url = 'url',
}

export interface TranscriptionSegment {
  speaker: string;
  transcript: string;
}

export interface TranscriptionResult {
  callerName: string;
  responderNames: string[];
  inquiryType: '訃報' | '事前相談' | '自身の事前相談' | '参列問い合わせ' | '供花、供物の注文依頼' | 'その他';
  details: string[];
  transcription: TranscriptionSegment[];
}

