export default function App() {
  const [inputMethod, setInputMethod] = useState<InputMethod>(InputMethod.File);
  const [audioFile, setAudioFile] = useState<File | null>(null);
  const [audioUrl, setAudioUrl] = useState<string>('');
  const [result, setResult] = useState<TranscriptionResult | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const handleTranscribe = useCallback(async () => {
    setIsLoading(true);
    setError(null);
    setResult(null);

    try {
      let audioData;
      if (inputMethod === InputMethod.File && audioFile) {
        const base64 = await fileToBase64(audioFile);
        audioData = { mimeType: audioFile.type, data: base64 };
      } else {
        audioData = await fetchAndEncodeAudio(audioUrl);
      }
      const data = await transcribeAudio(audioData);
      setResult(data);
    } catch (e: any) {
      setError(e.message);
    } finally {
      setIsLoading(false);
    }
  }, [audioFile, audioUrl, inputMethod]);

  return (
    <div className="min-h-screen bg-slate-50 p-4 sm:p-8">
      <div className="max-w-3xl mx-auto space-y-8">
        <header className="text-center space-y-2">
          <h1 className="text-3xl font-bold text-slate-900">葬儀社用 電話解析ツール</h1>
          <p className="text-slate-500">Gemini AIが電話の内容を自動で整理します</p>
        </header>

        <section className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 space-y-6">
          <InputModeToggle selectedMode={inputMethod} onModeChange={setInputMethod} disabled={isLoading} />
          {inputMethod === InputMethod.File ? (
            <FileInputForm file={audioFile} onFileChange={setAudioFile} isLoading={isLoading} />
          ) : (
            <UrlInputForm url={audioUrl} onUrlChange={setAudioUrl} isLoading={isLoading} />
          )}

          <button
            onClick={handleTranscribe}
            disabled={isLoading || (!audioFile && !audioUrl)}
            className="w-full py-4 bg-sky-600 text-white rounded-xl font-bold hover:bg-sky-700 disabled:bg-slate-300 transition-all flex items-center justify-center space-x-2"
          >
            {isLoading ? <Spinner /> : <span>解析を開始する</span>}
          </button>
        </section>

        {error && (
          <div className="bg-red-50 border border-red-200 text-red-700 p-4 rounded-xl flex items-center space-x-3">
            <InfoIcon />
            <span>{error}</span>
          </div>
        )}

        {result && (
          <section className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <ResultDisplay result={result} />
          </section>
        )}
      </div>
    </div>
  );
}

