              items: { type: Type.STRING },
              description: "応対者の名前リスト（必ずひらがな、登場順）",
            },
            inquiryType: {
              type: Type.STRING,
              enum: ['訃報', '事前相談', '自身の事前相談', '参列問い合わせ', '供花、供物の注文依頼', 'その他'],
              description: "問い合わせのカテゴリー",
            },
            details: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "具体的な内容の箇条書き（文頭の・は含めない）",
            },
            transcription: {
